 *   1. Validate pool_buffer and pool_size (must be at least sizeof(size_t)).
 *   2. Read the current used length from the header.
 *   3. If init_data is NULL:
 *        - data_len must be 0; otherwise fail.
 *        - No allocation is performed, return success.
 *   4. If init_data is not NULL:
 *        - Ensure data_len bytes fit into the remaining space.
 *        - Copy data_len bytes from init_data to the pool.
 *        - Update the used length and write it back to the header.
 *
 * Return values:
 *   0  – Success
 *  -1  – Failure (invalid parameters or insufficient space)
 */

#include <stddef.h>
#include <string.h>

/**
 * Allocate memory from the memory pool and initialize with data.
 *
 * @param init_data  Pointer to the initialization data to copy into the
 *                   allocated block.  May be NULL only if data_len is 0.
 * @param data_len   Number of bytes to allocate and copy.
 * @param pool_buffer Pointer to the memory pool buffer.
 * @param pool_size   Total size of the pool buffer in bytes.
 *
 * @return 0 on success, -1 on failure.
 */
int allocate_pool_memory(const char *init_data, size_t data_len,
                         char *pool_buffer, size_t pool_size)
{
    /* -----------------------------------------------------------------
     * Step 1: Basic validation.
     * ----------------------------------------------------------------- */
    if (pool_buffer == NULL) {
        return -1;
    }
    if (pool_size < sizeof(size_t)) {
        return -1;
    }

    /* -----------------------------------------------------------------
     * Step 2: Determine the usable region.
     * ----------------------------------------------------------------- */
    const size_t offset    = sizeof(size_t);               /* header size */
    const size_t available = pool_size - offset;           /* user‑data space */

    /* -----------------------------------------------------------------
     * Step 3: Read current used length.
     * ----------------------------------------------------------------- */
    size_t used = *(size_t *)pool_buffer;

    /* Guard against a corrupted header. */
    if (used > available) {
        return -1;
    }

    /* -----------------------------------------------------------------
     * Step 4: Handle the case where no data is supplied.
     * ----------------------------------------------------------------- */
    if (init_data == NULL) {
        /* NULL pointer is only allowed when no bytes are requested. */
        if (data_len != 0) {
            return -1;
        }
        /* No allocation needed. */
        return 0;
    }

    /* Zero‑length allocation is allowed but does nothing. */
    if (data_len == 0) {
        return 0;
    }

    /* -----------------------------------------------------------------
     * Step 5: Verify sufficient space remains.
     * ----------------------------------------------------------------- */
    if (data_len > available - used) {
        return -1;   /* Not enough room */
    }

    /* -----------------------------------------------------------------
     * Step 6: Perform the copy.
     * ----------------------------------------------------------------- */
    char *dest = pool_buffer + offset + used;
    memcpy(dest, init_data, data_len);

    /* -----------------------------------------------------------------
     * Step 7: Update the used length and write it back to the header.
     * ----------------------------------------------------------------- */
    used += data_len;
    *(size_t *)pool_buffer = used;

    return 0;
}
